// Categorize loan risk based on multiple factors
const loan = $input.first().json.loans[$index];

// Initialize risk score (0-100, higher = more risky)
let riskScore = 0;
let riskCategory = 'Low';
let actionsRequired = [];
let priority = 'Low';

// 1. Payment Delinquency Scoring
if (loan.daysPastDue > 60) {
  riskScore += 40;
  actionsRequired.push('Immediate collection action required');
} else if (loan.daysPastDue > 30) {
  riskScore += 25;
  actionsRequired.push('Follow-up payment reminder');
} else if (loan.daysPastDue > 15) {
  riskScore += 10;
  actionsRequired.push('Send payment reminder');
}

// 2. Debt-to-Income Ratio Scoring
if (loan.debtToIncomeRatio > 60) {
  riskScore += 35;
  actionsRequired.push('Review member income sources');
} else if (loan.debtToIncomeRatio > 45) {
  riskScore += 20;
  actionsRequired.push('Monitor income changes');
} else if (loan.debtToIncomeRatio > 35) {
  riskScore += 10;
}

// 3. Collateral Coverage Scoring
const coverageRatio = (loan.collateralValue / loan.outstandingBalance) * 100;
if (coverageRatio < 100) {
  riskScore += 30;
  actionsRequired.push('Request additional collateral');
} else if (coverageRatio < 120) {
  riskScore += 15;
  actionsRequired.push('Monitor collateral value');
}

// 4. Loan Concentration Scoring
// Assuming large loans are riskier
if (loan.outstandingBalance > 500000) {
  riskScore += 15;
}

// Determine final risk category
if (riskScore >= 60) {
  riskCategory = 'High';
  priority = 'High';
} else if (riskScore >= 30) {
  riskCategory = 'Medium';
  priority = 'Medium';
}

// Add monitoring metadata
const assessment = {
  loanId: loan.loanId,
  memberId: loan.memberId,
  memberName: loan.memberName,
  riskScore: riskScore,
  riskCategory: riskCategory,
  previousRiskCategory: loan.riskCategory,
  riskChanged: riskCategory !== loan.riskCategory,
  assessmentDate: new Date().toISOString(),
  riskFactors: {
    daysPastDue: loan.daysPastDue,
    debtToIncomeRatio: loan.debtToIncomeRatio,
    collateralCoverage: coverageRatio.toFixed(2) + '%',
    outstandingBalance: loan.outstandingBalance
  },
  actionsRequired: actionsRequired,
  priority: priority,
  followUpDeadline: riskCategory === 'High' ? 
    'Immediate' : 
    riskCategory === 'Medium' ? 
    'Within 3 days' : 
    'Next routine check'
};

// Update the loan object with new risk assessment
loan.riskCategory = riskCategory;
loan.lastAssessmentDate = new Date().toISOString();
loan.priority = priority;

return [
  {
    json: {
      originalLoan: loan,
      riskAssessment: assessment
    }
  }
];

