// Generate monitoring report
const riskAssessment = $input.first().json.riskAssessment;
const loan = $input.first().json.originalLoan;

// Create report entry
const reportEntry = {
  timestamp: new Date().toISOString(),
  monitoringRunId: 'MON-' + Date.now(),
  loanId: riskAssessment.loanId,
  memberId: riskAssessment.memberId,
  riskScore: riskAssessment.riskScore,
  riskCategory: riskAssessment.riskCategory,
  previousRiskCategory: riskAssessment.previousRiskCategory,
  riskChanged: riskAssessment.riskChanged,
  actionsTriggered: riskAssessment.actionsRequired,
  priority: riskAssessment.priority,
  details: {
    outstandingBalance: loan.outstandingBalance,
    daysPastDue: loan.daysPastDue,
    debtToIncomeRatio: loan.debtToIncomeRatio,
    collateralValue: loan.collateralValue
  }
};

// Store in Google Sheets (example)
// In practice, you would use Google Sheets node
// This returns data for the next node
return [
  {
    json: reportEntry,
    pairedItem: {
      item: 0
    }
  }
];

// Aggregate all monitoring results
const allResults = $input.all();

let highRiskCount = 0;
let mediumRiskCount = 0;
let lowRiskCount = 0;
let totalExposure = 0;
const changedLoans = [];
const highRiskLoans = [];

allResults.forEach(result => {
  const assessment = result.json.riskAssessment;
  const loan = result.json.originalLoan;

  totalExposure += loan.outstandingBalance;

  if (assessment.riskCategory === 'High') {
    highRiskCount++;
    highRiskLoans.push({
      loanId: assessment.loanId,
      memberName: assessment.memberName,
      riskScore: assessment.riskScore,
      outstandingBalance: loan.outstandingBalance
    });
  } else if (assessment.riskCategory === 'Medium') {
    mediumRiskCount++;
  } else {
    lowRiskCount++;
  }

  if (assessment.riskChanged) {
    changedLoans.push({
      loanId: assessment.loanId,
      from: assessment.previousRiskCategory,
      to: assessment.riskCategory
    });
  }
});

// Generate executive summary
const summaryReport = {
  reportDate: new Date().toISOString(),
  monitoringPeriod: 'Daily Monitoring Run',
  totalLoansAssessed: allResults.length,
  riskDistribution: {
    highRisk: highRiskCount,
    mediumRisk: mediumRiskCount,
    lowRisk: lowRiskCount
  },
  totalExposure: totalExposure,
  averageRiskScore: (allResults.reduce((sum, r) => sum + r.json.riskAssessment.riskScore, 0) / allResults.length).toFixed(2),
  riskCategoryChanges: changedLoans.length,
  highRiskExposure: highRiskLoans.reduce((sum, loan) => sum + loan.outstandingBalance, 0),
  details: {
    highRiskLoans: highRiskLoans,
    changedLoans: changedLoans
  },
  recommendations: [
    highRiskCount > 2 ? 'Schedule emergency credit committee meeting' : null,
    mediumRiskCount > 5 ? 'Increase monitoring frequency for medium-risk portfolio' : null,
    totalExposure > 5000000 ? 'Review portfolio concentration limits' : null
  ].filter(r => r !== null)
};

// Format as downloadable JSON
const jsonContent = JSON.stringify(summaryReport, null, 2);
const fileName = `loan-monitoring-report-${new Date().toISOString().split('T')[0]}.json`;

return [
  {
    json: summaryReport,
    binary: {
      data: {
        data: Buffer.from(jsonContent).toString('base64'),
        mimeType: 'application/json',
        fileName: fileName
      }
    }
  }
];
